def normalize_llm_provider(provider: Optional[str]) -> str:
    raw = (provider or "").strip().lower()
    aliases = {
        "": "auto",
        "auto": "auto",
        "automatic": "auto",
        "detect": "auto",
        "auto detect": "auto",
        "google": "gemini",
        "google ai": "gemini",
        "gemini": "gemini",
        "gemini api": "gemini",
        "openai": "openai",
        "chatgpt": "openai",
        "chatgpt api": "openai",
        "openai api": "openai",
        "gpt": "openai",
        "anthropic": "anthropic",
        "anthropic api": "anthropic",
        "claude": "anthropic",
        "claude api": "anthropic",
        "xai": "xai",
        "x.ai": "xai",
        "grok": "xai",
        "grok api": "xai",
    }
    normalized = aliases.get(raw, raw)
    return normalized if normalized in set(SUPPORTED_LLM_PROVIDERS) | {"auto"} else "auto"

def get_provider_display_name(provider: Optional[str]) -> str:
    return PROVIDER_DISPLAY_NAMES.get(normalize_llm_provider(provider), "Auto detect")

def is_placeholder_api_key(api_key: Optional[str]) -> bool:
    key = (api_key or "").strip()
    if not key:
        return False
    normalized = re.sub(r"[^a-z0-9]+", "_", key.lower()).strip("_")
    return any(marker in normalized for marker in PLACEHOLDER_API_KEY_MARKERS)

def detect_provider_from_api_key(api_key: Optional[str]) -> Optional[str]:
    key = (api_key or "").strip()
    if is_placeholder_api_key(key):
        return None
    if not key:
        return None
    low = key.lower()
    if key.startswith("AIza"):
        return "gemini"
    if low.startswith("sk-ant-"):
        return "anthropic"
    if low.startswith("xai-"):
        return "xai"
    if low.startswith("sk-proj-") or low.startswith("sk-"):
        return "openai"
    return None

def get_env_api_key_for_provider(provider: Optional[str]) -> str:
    env_var = PROVIDER_ENV_KEY_VARS.get(normalize_llm_provider(provider), "")
    if not env_var:
        return ""
    value = (os.getenv(env_var, "") or "").strip()
    return "" if is_placeholder_api_key(value) else value

def get_provider_model_presets(provider: Optional[str]) -> List[str]:
    normalized = normalize_llm_provider(provider)
    if normalized not in SUPPORTED_LLM_PROVIDERS:
        return []
    env_var = PROVIDER_ENV_MODEL_VARS.get(normalized, "")
    env_model = (os.getenv(env_var, "") or "").strip() if env_var else ""
    ordered: List[str] = []
    seen = set()
    for name in [env_model, *PROVIDER_MODEL_PRESETS.get(normalized, ())]:
        model_name = (name or "").strip()
        if not model_name or model_name in seen:
            continue
        seen.add(model_name)
        ordered.append(model_name)
    return ordered

def get_default_model_for_provider(provider: Optional[str]) -> str:
    normalized = normalize_llm_provider(provider)
    if normalized not in SUPPORTED_LLM_PROVIDERS:
        return ""
    env_var = PROVIDER_ENV_MODEL_VARS.get(normalized, "")
    env_model = (os.getenv(env_var, "") or "").strip() if env_var else ""
    if env_model:
        return env_model
    presets = get_provider_model_presets(normalized)
    if presets:
        return presets[0]
    if normalized == "gemini":
        return GEMINI_MODEL_NAME
    return ""

def get_provider_model_placeholder(provider: Optional[str]) -> str:
    default_model = get_default_model_for_provider(provider)
    if default_model:
        return default_model
    return PROVIDER_MODEL_PLACEHOLDERS.get(normalize_llm_provider(provider), "")

def resolve_provider_api_key(provider: Optional[str], entered_api_key: Optional[str]) -> str:
    entered = (entered_api_key or "").strip()
    if entered and not is_placeholder_api_key(entered):
        return entered
    return get_env_api_key_for_provider(provider)

def resolve_llm_provider(provider_choice: Optional[str], api_key: Optional[str] = None) -> str:
    normalized = normalize_llm_provider(provider_choice)
    if normalized in SUPPORTED_LLM_PROVIDERS:
        return normalized

    detected = detect_provider_from_api_key(api_key)
    if detected:
        return detected

    preferred_env = normalize_llm_provider(os.getenv("LEGAL_AI_PROVIDER", ""))
    if preferred_env in SUPPORTED_LLM_PROVIDERS and get_env_api_key_for_provider(preferred_env):
        return preferred_env

    for provider in SUPPORTED_LLM_PROVIDERS:
        if get_env_api_key_for_provider(provider):
            return provider

    return preferred_env if preferred_env in SUPPORTED_LLM_PROVIDERS else "gemini"

def resolve_model_name_for_provider(provider: Optional[str], entered_model_name: Optional[str]) -> str:
    entered = (entered_model_name or "").strip()
    if entered:
        return entered

    return get_default_model_for_provider(provider)

def _openai_base_url_for_provider(provider: str) -> Optional[str]:
    normalized = normalize_llm_provider(provider)
    if normalized == "xai":
        return (os.getenv("XAI_BASE_URL", "https://api.x.ai/v1") or "https://api.x.ai/v1").strip()
    return None

class _SimpleTextResponse:
    def __init__(self, text: str):
        self.text = text


def _anthropic_default_max_output_tokens(model_name: str) -> int:
    override = (os.getenv("ANTHROPIC_MAX_OUTPUT_TOKENS", "") or "").strip()
    if override.isdigit():
        return max(1024, int(override))

    normalized = (model_name or "").strip().lower()
    if "claude-sonnet-4" in normalized or "claude-3-7-sonnet" in normalized:
        return 16000
    if "claude-opus-4" in normalized:
        return 12000
    if "claude-3-5" in normalized:
        return 8192
    return 8192


class _OpenAICompatibleChatAdapter:
    def __init__(
        self,
        *,
        provider: str,
        api_key: str,
        model_name: str,
        system_instruction: str,
        history: Optional[List[Dict[str, Any]]] = None,
    ) -> None:
        if not OPENAI_SDK_AVAILABLE or OpenAI is None:
            raise RuntimeError("OpenAI SDK is not installed; OpenAI/xAI providers are unavailable.")
        client_kwargs: Dict[str, Any] = {"api_key": api_key}
        base_url = _openai_base_url_for_provider(provider)
        if base_url:
            client_kwargs["base_url"] = base_url
        self.client = OpenAI(**client_kwargs)
        self.provider = normalize_llm_provider(provider)
        self.model_name = model_name
        self.system_instruction = system_instruction
        self.history = history or []

    def _messages_for_prompt(self, prompt_text: str) -> List[Dict[str, str]]:
        messages: List[Dict[str, str]] = [{"role": "system", "content": self.system_instruction}]
        for msg in self.history:
            msg_text = (msg.get("text") or "").strip()
            if not msg_text:
                continue
            role = "user" if msg.get("role") == "user" else "assistant"
            messages.append({"role": role, "content": msg_text})
        messages.append({"role": "user", "content": prompt_text})
        return messages

    @staticmethod
    def _extract_text_from_completion(response: Any) -> str:
        try:
            content = response.choices[0].message.content
            if isinstance(content, str):
                return content
            if isinstance(content, list):
                out_parts: List[str] = []
                for item in content:
                    if isinstance(item, dict):
                        if item.get("type") == "text" and isinstance(item.get("text"), str):
                            out_parts.append(item["text"])
                    else:
                        text_val = getattr(item, "text", None)
                        if isinstance(text_val, str) and text_val:
                            out_parts.append(text_val)
                return "".join(out_parts)
        except Exception:
            pass
        return ""

    @staticmethod
    def _stream_text_chunks(raw_stream: Iterable[Any]) -> Iterable[Dict[str, str]]:
        for chunk in raw_stream:
            text = ""
            try:
                delta = chunk.choices[0].delta
                content = getattr(delta, "content", None)
                if isinstance(content, str):
                    text = content
                elif isinstance(content, list):
                    parts: List[str] = []
                    for item in content:
                        if isinstance(item, dict):
                            if item.get("type") == "text" and isinstance(item.get("text"), str):
                                parts.append(item["text"])
                        else:
                            text_val = getattr(item, "text", None)
                            if isinstance(text_val, str) and text_val:
                                parts.append(text_val)
                    text = "".join(parts)
            except Exception:
                text = ""
            if text:
                yield {"text": text}

    def send_message(self, prompt_text: str, stream: bool = False) -> Any:
        messages = self._messages_for_prompt(prompt_text)
        if stream:
            raw_stream = self.client.chat.completions.create(
                model=self.model_name,
                messages=messages,
                stream=True,
            )
            return self._stream_text_chunks(raw_stream)
        response = self.client.chat.completions.create(
            model=self.model_name,
            messages=messages,
        )
        return _SimpleTextResponse(self._extract_text_from_completion(response))


class _AnthropicChatAdapter:
    def __init__(
        self,
        *,
        api_key: str,
        model_name: str,
        system_instruction: str,
        history: Optional[List[Dict[str, Any]]] = None,
    ) -> None:
        if not ANTHROPIC_SDK_AVAILABLE or Anthropic is None:
            raise RuntimeError("Anthropic SDK is not installed; Anthropic/Claude provider is unavailable.")
        self.client = Anthropic(api_key=api_key)
        self.model_name = model_name
        self.system_instruction = system_instruction
        self.history = history or []
        self.max_output_tokens = _anthropic_default_max_output_tokens(model_name)

    def _messages_for_prompt(self, prompt_text: str) -> List[Dict[str, str]]:
        messages: List[Dict[str, str]] = []
        for msg in self.history:
            msg_text = (msg.get("text") or "").strip()
            if not msg_text:
                continue
            role = "user" if msg.get("role") == "user" else "assistant"
            messages.append({"role": role, "content": msg_text})
        messages.append({"role": "user", "content": prompt_text})
        return messages

    @staticmethod
    def _extract_text_from_completion(response: Any) -> str:
        parts: List[str] = []
        for item in getattr(response, "content", []) or []:
            item_type = getattr(item, "type", None)
            item_text = getattr(item, "text", None)
            if item_type == "text" and isinstance(item_text, str) and item_text:
                parts.append(item_text)
        return "".join(parts)

    def send_message(self, prompt_text: str, stream: bool = False) -> Any:
        messages = self._messages_for_prompt(prompt_text)
        if stream:
            def _stream_chunks() -> Iterable[Dict[str, str]]:
                with self.client.messages.stream(
                    model=self.model_name,
                    max_tokens=self.max_output_tokens,
                    system=self.system_instruction,
                    messages=messages,
                ) as raw_stream:
                    for text in raw_stream.text_stream:
                        if isinstance(text, str) and text:
                            yield {"text": text}
            return _stream_chunks()

        response = self.client.messages.create(
            model=self.model_name,
            max_tokens=self.max_output_tokens,
            system=self.system_instruction,
            messages=messages,
        )
        return _SimpleTextResponse(self._extract_text_from_completion(response))

